  <div className="d-flex flex-column align-items-center mt-4">
    <Typography
      as="h1"
      className="pb-3 pt-3"
      css={css(
        typography.styles.headingBold28,
        media.queryStyled([
          typography.styles.headingBold28,
          typography.styles.headingBold28,
          typography.styles.headingBold34,
